<script setup lang="ts">
import type { JobRecord } from '../../shared/contracts'
interface Props { job: JobRecord }
interface Emits { control: [id: string, action: 'pause' | 'resume' | 'cancel'] }
defineProps<Props>()
defineEmits<Emits>()
</script>
<template><v-hover v-slot="hover"><v-card v-bind="hover?.props" class="glass module-card pa-5" :class="{'is-hovered':Boolean(hover?.isHovering)}"><div class="d-flex justify-space-between align-center"><div><div class="text-overline text-primary">{{ job.kind }}</div><div class="text-h6 font-weight-bold">{{ job.title }}</div></div><v-chip :color="job.status==='completed'?'success':job.status==='recoverable'?'warning':job.status==='failed'?'error':'primary'" variant="tonal">{{ job.status }}</v-chip></div><div class="d-flex justify-space-between text-caption text-medium-emphasis mt-5"><span>{{ job.stage }}</span><span>{{ Math.round(job.progress) }}%</span></div><v-progress-linear :model-value="job.progress" color="primary" rounded height="8" class="mt-2"/><div class="d-flex ga-2 mt-4"><v-btn v-if="job.status==='running'" size="small" variant="tonal" prepend-icon="mdi-pause" @click="$emit('control',job.id,'pause')">Pause</v-btn><v-btn v-if="job.status==='paused'||job.status==='recoverable'" size="small" color="primary" prepend-icon="mdi-play" @click="$emit('control',job.id,'resume')">Resume</v-btn><v-btn v-if="!['completed','cancelled'].includes(job.status)" size="small" color="error" variant="text" prepend-icon="mdi-close" @click="$emit('control',job.id,'cancel')">Cancel</v-btn></div><v-alert v-if="job.error" type="warning" variant="tonal" density="compact" class="mt-4">{{ job.error }}</v-alert></v-card></v-hover></template>
